use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::thread;

#[derive(Debug, Clone, PartialEq)]
pub enum InventoryError {
    InsufficientStock,
    ProductNotFound,
}

pub struct Inventory {
    stock: Mutex<HashMap<String, u32>>,
}

impl Inventory {
    pub fn new() -> Self {
        Inventory {
            stock: Mutex::new(HashMap::new()),
        }
    }

    pub fn add_product(&self, product_id: String, quantity: u32) {
        let mut stock = self.stock.lock().unwrap();
        *stock.entry(product_id).or_insert(0) += quantity;
    }

    pub fn check_stock(&self, product_id: &str) -> Option<u32> {
        let stock = self.stock.lock().unwrap();
        stock.get(product_id).copied()
    }

    pub fn decrement_stock(&self, product_id: &str, quantity: u32) -> Result<(), InventoryError> {
        let mut stock = self.stock.lock().unwrap();
        
        let current_stock = stock.get(product_id)
            .ok_or(InventoryError::ProductNotFound)?;
        
        if *current_stock < quantity {
            return Err(InventoryError::InsufficientStock);
        }
        
        *stock.get_mut(product_id).unwrap() -= quantity;
        Ok(())
    }

    pub fn try_purchase(&self, product_id: &str, quantity: u32) -> Result<(), InventoryError> {
        self.decrement_stock(product_id, quantity)
    }

    pub fn batch_purchase(&self, items: Vec<(String, u32)>) -> Result<(), InventoryError> {
        let mut stock = self.stock.lock().unwrap();
        
        for (product_id, quantity) in &items {
            let current_stock = stock.get(product_id.as_str())
                .ok_or(InventoryError::ProductNotFound)?;
            
            if *current_stock < *quantity {
                return Err(InventoryError::InsufficientStock);
            }
        }
        
        for (product_id, quantity) in items {
            *stock.get_mut(product_id.as_str()).unwrap() -= quantity;
        }
        
        Ok(())
    }
}

pub fn run_concurrent_inventory_test() {
    let inventory = Arc::new(Inventory::new());
    
    inventory.add_product("PRODUCT_A".to_string(), 1000);
    inventory.add_product("PRODUCT_B".to_string(), 500);
    
    let mut handles = vec![];
    
    for i in 0..10 {
        let inv = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            for j in 0..100 {
                let product = if (i + j) % 2 == 0 { "PRODUCT_A" } else { "PRODUCT_B" };
                match inv.try_purchase(product, 1) {
                    Ok(_) => {},
                    Err(e) => eprintln!("Thread {} failed to purchase {}: {:?}", i, product, e),
                }
            }
        });
        handles.push(handle);
    }
    
    for handle in handles {
        handle.join().unwrap();
    }
    
    println!("Final stock PRODUCT_A: {:?}", inventory.check_stock("PRODUCT_A"));
    println!("Final stock PRODUCT_B: {:?}", inventory.check_stock("PRODUCT_B"));
}